import json
with open('.yoyo/state/events.jsonl') as f:
    total = 0
    missing = 0
    sample_missing = []
    for line in f:
        line = line.strip()
        if not line:
            continue
        try:
            ev = json.loads(line)
            total += 1
            if 'event_type' not in ev:
                missing += 1
                if len(sample_missing) < 5:
                    sample_missing.append(json.dumps({k: ev.get(k) for k in list(ev.keys())[:5]}, default=str)[:200])
        except:
            pass
print(f'Total: {total}, Missing event_type: {missing}')
for s in sample_missing:
    print(f'  {s}')
"

