args.command:
python3 -c "
import json
from collections import Counter
kinds = Counter()
with open('.yoyo/state/events.jsonl') as f:
    for line in f:
        line = line.strip()
        if not line:
            continue
        try:
            ev = json.loads(line)
            if 'event_type' not in ev:
                k = ev.get('kind', 'MISSING_BOTH')
                kinds[k] += 1
        except:
            pass
for k, v in kinds.most_common(20):
    print(f'{k}: {v}')
"

